  it("customer with exactly 2 years, sword → 100 - 20 loyalty + 10 first + 5 fee = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });

  // === Rounding in MHPCO's favor ===
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");

  // === Integration: Newcomer with cursed sword ===
  it.todo("newcomer (0 years, first contract), cursed sword (steel, ench 3) → premium 165 G");

  // === Integration: Long-standing customer's 2nd contract ===
  it.todo("3 years customer, 2nd quote, cursed sword (steel, ench 7) → premium 160 G");

  // === Follow-up contract discount: each item still treated as first insurance ===
  it.todo("follow-up contract: first-insurance surcharge still applies per item");

  // === Claim: standard reimbursement ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 G → payout 100 G (200 - 100 deductible)");

  // === Claim: deductible per item ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // === Claim: high-enchantment clause ===
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible)");

  // === Claim: dragon material clause ===
  it.todo("dragon sword, ench 5, damage 800 → payout 700 (full then deductible)");

  // === Claim: both clauses → 50% wins ===
  it.todo("dragon sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");

  // === Cap exhaustion ===
  it.todo("sword (1000), cap 2000; first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (1000), cap 2000; first claim 1500 (payout 1400), second claim 1500 → payout 600, remainingCap 0");

