type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const groupPremium = (type: string, count: number): number =>
  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
  return counts;
};

const basePremiumForItems = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + groupPremium(type, count),
    0,
  );

const perItemSurcharge = (
  items: Item[],
  appliesTo: (item: Item) => boolean,
  rate: number,
): number =>
  items
    .filter(appliesTo)
    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const withFirstInsuranceSurcharge = (amount: number): number =>
  amount + amount * FIRST_INSURANCE_SURCHARGE;

const itemizedPremium = (items: Item[]): number =>
  basePremiumForItems(items)
  + perItemSurcharge(items, isCursed, CURSE_SURCHARGE)
  + perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);

const quotePremium = ({ items }: QuoteStep): QuoteResult => {
  const perItemSubtotal = itemizedPremium(items);
  const afterFirstInsurance = withFirstInsuranceSurcharge(perItemSubtotal);
  const totalBeforeRounding = afterFirstInsurance + PROCESSING_FEE;
  return { premium: Math.ceil(totalBeforeRounding) };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map(quotePremium),
});

