import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Empty / processing fee ===
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // === Single item base premiums (no modifiers, no fee logic yet beyond minimum) ===
  it("single sword (no modifiers, newcomer first contract) → 100 + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (no modifiers, newcomer first contract) → 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (no modifiers, newcomer first contract) → 80 + 8 first + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (no modifiers, newcomer first contract) → 40 + 4 first + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // === Components and blocks (base premium examples) ===
  it("2 runes → 50 G base premium (no block) → +10% first +5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies) → +10% first +5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base premium (no block) → 110 + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base premium → +10% first +5 fee = 198 G (ceil 197.5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: Array.from({ length: 7 }, () => ({ type: "rune" })),
      }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // === Alike components: same type only ===
  it("2 runes + 1 moonstone → 75 G base premium → +10% first +5 fee = 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) → +10% first +5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // === Cursed surcharge ===
  it("cursed sword (newcomer, first contract) → 100 base + 50 curse + 10 first +5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });

  // === Modifier scope: per-item surcharges vs policy-wide modifiers ===
  it("cursed sword + plain amulet → 160 base + 50 curse + 16 first (10% of 160) + 5 fee = 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", cursed: true }, { type: "amulet" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // === High-enchantment surcharge ===
  it("sword with enchantment 5 (newcomer, first contract) → 100+30+10 first +5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge → 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("sword with enchantment 5 AND cursed → both surcharges apply → 100+50+30+10 first +5 fee = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // === Loyalty discount ===
  it("customer with exactly 2 years, sword → 100 - 20 loyalty + 10 first + 5 fee = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });

  // === Rounding in MHPCO's favor ===
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");

  // === Integration: Newcomer with cursed sword ===
  it.todo("newcomer (0 years, first contract), cursed sword (steel, ench 3) → premium 165 G");

  // === Integration: Long-standing customer's 2nd contract ===
  it.todo("3 years customer, 2nd quote, cursed sword (steel, ench 7) → premium 160 G");

  // === Follow-up contract discount: each item still treated as first insurance ===
  it.todo("follow-up contract: first-insurance surcharge still applies per item");

  // === Claim: standard reimbursement ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 G → payout 100 G (200 - 100 deductible)");

  // === Claim: deductible per item ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // === Claim: high-enchantment clause ===
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible)");

  // === Claim: dragon material clause ===
  it.todo("dragon sword, ench 5, damage 800 → payout 700 (full then deductible)");

  // === Claim: both clauses → 50% wins ===
  it.todo("dragon sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");

  // === Cap exhaustion ===
  it.todo("sword (1000), cap 2000; first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword (1000), cap 2000; first claim 1500 (payout 1400), second claim 1500 → payout 600, remainingCap 0");

  // === Insurance sum / cap calculation ===
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (modifiers do not raise cap)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block affects premium, not sum)");

  // === Multiple items of same type ===
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
  it.todo("damages array contains more entries than policy covers → CLI exits non-zero");

  // === Edge cases ===
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr");
  it.todo("claim damages references item not in policy → CLI exits non-zero, stderr error");
  it.todo("claim with damage amount -200 → CLI exits non-zero, stderr error");
});

