const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const groupPremium = (type: string, count: number): number =>
  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
  return counts;
};

const sumBasePremiumsByGroup = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + groupPremium(type, count),
    0,
  );

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const surchargeOnMatching = (
  items: Item[],
  predicate: (item: Item) => boolean,
  rate: number,
): number =>
  items
    .filter(predicate)
    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);

const perItemSurcharges = (items: Item[]): number =>
  surchargeOnMatching(items, isCursed, CURSE_SURCHARGE)
  + surchargeOnMatching(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);

const policyWideAdjustments = (policyBase: number, customer: Customer): number => {
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  const loyalty = isLoyalCustomer(customer) ? -policyBase * LOYALTY_DISCOUNT : 0;
  return firstInsurance + loyalty;
};

const quotePremiumFor = (customer: Customer) =>
  ({ items }: QuoteStep): QuoteResult => {
    const policyBase = sumBasePremiumsByGroup(items);
    const total =
      policyBase
      + perItemSurcharges(items)
      + policyWideAdjustments(policyBase, customer)
      + PROCESSING_FEE;
    return { premium: Math.ceil(total) };
  };

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map(quotePremiumFor(scenario.customer)),
});

