const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;
const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;

toolUseResult.originalFile:
type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
type Customer = { yearsWithMHPCO: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Damage = { itemType: string; amount: number };
type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
type Step = QuoteStep | ClaimStep;
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const groupPremium = (type: string, count: number): number =>
  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
  return counts;
};

const sumBasePremiumsByGroup = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + groupPremium(type, count),
    0,
  );

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const surchargeOnMatching = (
  items: Item[],
  predicate: (item: Item) => boolean,
  rate: number,
): number =>
  items
    .filter(predicate)
    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);

const perItemSurcharges = (items: Item[]): number =>
  surchargeOnMatching(items, isCursed, CURSE_SURCHARGE)
  + surchargeOnMatching(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);

const policyWideAdjustments = (policyBase: number, customer: Customer): number => {
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  const loyalty = isLoyalCustomer(customer) ? -policyBase * LOYALTY_DISCOUNT : 0;
  return firstInsurance + loyalty;
};

const quotePremiumFor = (customer: Customer, { items }: QuoteStep): QuoteResult => {
  const policyBase = sumBasePremiumsByGroup(items);
  const total =
    policyBase
    + perItemSurcharges(items)
    + policyWideAdjustments(policyBase, customer)
    + PROCESSING_FEE;
  return { premium: Math.ceil(total) };
};

type Policy = { items: Item[]; remainingCap: number };

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const createPolicy = ({ items }: QuoteStep): Policy => ({
  items,
  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
});

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const totalPayout = (damages: Damage[]): number =>
  damages.reduce((sum, d) => sum + payoutForDamage(d), 0);

const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
  const payout = totalPayout(incident.damages);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  const handle = (step: Step): StepResult => {
    if (step.op === "quote") {
      policies.push(createPolicy(step));
      return quotePremiumFor(customer, step);
    }
    return settleClaim(policies[step.policy], step);
  };
  return { results: steps.map(handle) };
};

